/* oms-report-DailyIbXObStatus-sql-oracle.xml selectDailyIbXObStatusList */ SELECT CNFRMDAY , OWKEY , CTKEY , CTNM , SUM(IBCNFRMQTY) AS IBCNFRMQTY , SUM(IBCNFRMINN) AS IBCNFRMINN , SUM(IBCNFRMCTN) AS IBCNFRMCTN , SUM(IBSLPRC) AS IBSLPRC , SUM(OBCNFRMQTY) AS OBCNFRMQTY , SUM(OBCNFRMINN) AS OBCNFRMINN , SUM(OBCNFRMCTN) AS OBCNFRMCTN , SUM(OBSLPRC) AS OBSLPRC FROM ( SELECT CNFRMDAY , OWKEY , CTKEY , CTNM , ICKEY , IBCNFRMQTY , CASE WHEN IBCNFRMQTY IS NULL OR IBCNFRMQTY = 0 THEN 0 ELSE ROUND(IBCNFRMQTY / IC_INN, 2) END AS IBCNFRMINN , CASE WHEN IBCNFRMQTY IS NULL OR IBCNFRMQTY = 0 THEN 0 ELSE ROUND(IBCNFRMQTY / IC_CTN, 2) END AS IBCNFRMCTN , ROUND(IBCNFRMQTY * SLPRC, 2) AS IBSLPRC , OBCNFRMQTY , CASE WHEN OBCNFRMQTY IS NULL OR OBCNFRMQTY = 0 THEN 0 ELSE ROUND(OBCNFRMQTY / IC_INN, 2) END AS OBCNFRMINN , CASE WHEN OBCNFRMQTY IS NULL OR OBCNFRMQTY = 0 THEN 0 ELSE ROUND(OBCNFRMQTY / IC_CTN, 2) END AS OBCNFRMCTN , ROUND(OBCNFRMQTY * SLPRC, 2) AS OBSLPRC FROM ( SELECT HD.CNFRMDAY , HD.OWKEY /* 화주코드 */ , HD.CTKEY /* 센터코드 */ , CT.CTNM , DT.ICKEY , COALESCE(CASE WHEN TP.IBYN = 'Y' THEN DT.CNFRMQTY END, 0) AS IBCNFRMQTY , COALESCE(CASE WHEN TP.OBYN = 'Y' THEN DT.CNFRMQTY END, 0) AS OBCNFRMQTY , IC_INN , IC_CTN , SLPRC FROM TORDER_INFO_SO_HD HD INNER JOIN TORDER_INFO_SO_DT DT ON HD.OWKEY = DT.OWKEY AND HD.SOHDKEY = DT.SOHDKEY INNER JOIN TORDER_MST_ORTYPE TP ON HD.OWKEY = TP.OWKEY AND HD.ORDERTYPECD = TP.ORDERTYPECD INNER JOIN TORDER_MST_IC IC ON DT.OWKEY = IC.OWKEY AND DT.ICKEY = IC.ICKEY INNER JOIN TORDER_MST_ICXCT ICXCT ON IC.OWKEY = ICXCT.OWKEY AND IC.ICKEY = ICXCT.ICKEY INNER JOIN TORDER_MST_CT CT ON ICXCT.CTKEY = CT.CTKEY INNER JOIN ( SELECT ICKEY , OWKEY , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'INN' THEN ICUNITQTY END), 1) AS IC_INN , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'CTN' THEN ICUNITQTY END), 1) AS IC_CTN FROM TORDER_MST_ICUTXTYPE WHERE OWKEY = #{owkey} GROUP BY ICKEY, OWKEY ) S_ICUT ON IC.OWKEY = S_ICUT.OWKEY AND IC.ICKEY = S_ICUT.ICKEY WHERE HD.WKSTATUS = #{soCompleteWkstatus}
AND #{SEARCH_CONDITION}
) F ) T WHERE CNFRMDAY BETWEEN #{orHddateFr} AND #{orHddateTo} GROUP BY CNFRMDAY, OWKEY, CTKEY, CTNM ORDER BY CNFRMDAY
